base_url &lt;- paste0("https://api.census.gov/data/2022/acs/acs1/pums?get=SEX,PWGTP,MAR&for=state:*&SCHL=24&key=",
                   api_key)

# removed to speed up render
#api_return &lt;- GET(base_url)

str(api_return)

