                    "&key=",
                    api_key)

  api_return &lt;- GET(api_url)
  api_parsed &lt;- fromJSON(rawToChar(api_return$content)) |&gt;
                as_tibble()

  # fix col names
  output &lt;- api_parsed
  names(output) &lt;- output[1,]
  output &lt;- output[-1,]

