Next, we can write a function to get data for multiple years:

query.census.multi &lt;- function(years = 2010:2022, numeric_vars = "AGEP", categorical_vars = "SEX", 
                               geography = "State", specific_geo = 4, return_url = FALSE) {
  if(min(years) &lt; 2010 | max(years) &gt; 2022) {
    stop("Error: Invalid year(s). Specify year(s) between 2010 and 2022")
  }

  output &lt;- tibble()

  for(i in years[years != 2020]) {
    year_data &lt;- query.census(year = i, numeric_vars = numeric_vars, categorical_vars = categorical_vars,
                              geography = geography, specific_geo = specific_geo)

    year_data$year &lt;- i

    output &lt;- rbind(output, year_data)
  }

  return(output)  
}

