fix.time &lt;- function (time) {
  library(lubridate)

  is_zero &lt;- time == 0

  scnds_since_midnight &lt;- 120 + (time-1)*300 + ifelse(time &gt; 6, 300, 0) + ifelse(time &gt; 9, 300, 0) + ifelse(time &gt; 20, 300, 0)

  scnds_since_midnight[is_zero] &lt;- 0

  return(hms::as_hms(scnds_since_midnight))
}

